"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[944],{944:function(e,i,o){o.d(i,{c8:function(){return t},lW:function(){return a},sS:function(){return n}});let n=[{title:{en:"Evolution of Cooperation",zh:"合作的演化"},description:{en:"Co-authored paper in Physical Review E on conditional cooperators.",zh:"在 Physical Review E 上共同发表了关于条件合作者的论文。"},technicalDescription:{en:"Q-learning models phase transitions in bimodal cooperation mixtures; published Physical Review E 112, 054309 (2025).",zh:"Q-learning 模型在双峰合作混合物中的相变；发表于 Physical Review E 112, 054309 (2025)。"},metric:{en:"Published \xb7 Physical Review E",zh:"已发表 \xb7 Physical Review E"},image:null,gradient:"var(--card-1-gradient)",alt:"Abstract visualization of cooperation dynamics and game theory"},{title:{en:"de Rham Cohomology Research",zh:"de Rham 上同调研究"},description:{en:"Studying smooth manifolds under Prof. Yanli Song at WashU.",zh:"在华大宋雁离教授指导下研究光滑流形。"},technicalDescription:{en:"Computing cohomology groups of classical manifolds via Mayer–Vietoris sequences and differential forms.",zh:"通过 Mayer–Vietoris 序列和微分形式计算经典流形的上同调群。"},metric:{en:"Ongoing \xb7 WashU Math",zh:"进行中 \xb7 华大数学"},image:null,gradient:"var(--card-2-gradient)",alt:"Mathematical diagram of manifold topology"},{title:{en:"Power Dynamics & Reinforcement Learning",zh:"权力动态与强化学习"},description:{en:"Studied how social hierarchy affects cooperation using Q-Tables.",zh:"利用 Q-Tables 研究社会等级如何影响合作。"},technicalDescription:{en:"Reinforcement learning (Q-Table) model of cooperation/defection dynamics under varying power hierarchies.",zh:"强化学习（Q-Table）模型，研究在不同权力等级下的合作/背叛动态。"},metric:{en:"RL \xb7 Game Theory",zh:"强化学习 \xb7 博弈论"},image:null,gradient:"var(--card-3-gradient)",alt:"Network graph of agents cooperating and defecting"},{title:{en:"Letter Recognition ML",zh:"字母识别机器学习"},description:{en:"SVM, Random Forest, and CNN to classify handwritten letters.",zh:"使用 SVM、随机森林和卷积神经网络对手写字母进行分类。"},technicalDescription:{en:"Multi-model comparison: SVC, Random Forest, and CNN for character classification and historical document digitization.",zh:"多模型对比：使用 SVC、随机森林和卷积神经网络进行字符分类和历史文档数字化。"},metric:{en:"CNN \xb7 SVM \xb7 RF",zh:"卷积神经网络 \xb7 支持向量机 \xb7 随机森林"},image:null,gradient:"var(--card-4-gradient)",alt:"Character recognition model architecture diagram"},{title:{en:"Robomaster Computer Vision",zh:"Robomaster 计算机视觉"},description:{en:"ML model training for robot competition at WashU Ursaworks.",zh:"在圣路易斯华盛顿大学 Ursaworks 机器人竞赛中进行的机器学习模型训练。"},technicalDescription:{en:"Dataset collection, video labeling, and model training for autonomous robot navigation in the Robomaster Competition.",zh:"在 Robomaster 竞赛中进行自动机器人导航的数据集收集、视频标注和模型训练。"},metric:{en:"CV \xb7 Robotics",zh:"计算机视觉 \xb7 机器人"},image:null,gradient:"var(--card-5-gradient)",alt:"Robot with computer vision detection bounding boxes"}],t=[{id:1,title:{en:"Evolution of Cooperation in a Bimodal Mixture of Conditional Cooperators",zh:"双峰条件合作者混合物中的合作演化"},shortDescription:{en:"Co-authored published research on evolutionary game theory",zh:"关于进化博弈论的已发表共同研究"},simpleDescription:{en:"Studied how different types of cooperative behavior emerge and evolve in populations, using an AI learning algorithm (Q-learning) to model how individuals adapt their strategies based on their social environment. Found that mixing behavioral types leads to surprising jumps in overall cooperation levels.",zh:"研究了不同类型的合作行为在人群中是如何出现和演变的，使用人工智能学习算法 (Q-learning) 来模拟个人如何根据社会环境调整其策略。发现混合行为类型会导致整体合作水平的惊人跃升。"},technicalDescription:{en:"Applied Q-learning from reinforcement learning to model soft conditional cooperation in a bimodal mixture of hard and soft conditional cooperators. Investigated structural mixture (SM) and probabilistic mixture (PM) scenarios. In PM, found two first-order phase transitions in cooperation prevalence. Published in Physical Review E 112, 054309 (2025). arXiv:2502.07537.",zh:"应用强化学习中的 Q-learning 来建模硬、软条件合作者的双峰混合中的软条件合作。研究了结构混合 (SM) 和概率混合 (PM) 场景。在 PM 中，发现合作流行程度的两次一阶相变。发表于 Physical Review E 112, 054309 (2025)。arXiv:2502.07537。"},techStack:["Python","Q-Learning","Reinforcement Learning","Game Theory","Statistical Physics"],category:{en:"Research",zh:"研究"},metrics:[{en:"Published in Physical Review E 112, 054309 (2025)",zh:"发表于 Physical Review E 112, 054309 (2025)"},{en:"Two first-order phase transitions identified in cooperation prevalence",zh:"在合作流行程度中确定了两次一阶相变"},{en:'Q-learning models adaptive "psychological shifts" in cooperation',zh:"Q-learning 模型描述合作中的适应性“心理转变”"},{en:"Robust findings confirmed across model extensions",zh:"通过模型扩展确认了稳健的研究结果"}],dataSources:[{en:"Evolutionary game theory simulations",zh:"进化博弈论模拟"},{en:"Multi-agent Q-learning environments",zh:"多智能体 Q-learning 环境"}],reportLink:"https://arxiv.org/abs/2502.07537",pdfLink:"https://arxiv.org/pdf/2502.07537",codeLink:"https://github.com/XinshiFeng",isPaper:!0,journal:"Physical Review E 112, 054309 (2025)",arxivId:"2502.07537"},{id:2,title:{en:"de Rham Cohomology in Manifold Theory",zh:"流形理论中的 de Rham 上同调"},shortDescription:{en:"Faculty-supervised research in smooth manifold topology",zh:"在教授指导下进行的光滑流形拓扑研究"},simpleDescription:{en:'Studying the mathematical structure of curved surfaces and higher-dimensional spaces, learning how to classify their "holes" and connectivity properties using a powerful tool from calculus called de Rham cohomology.',zh:"研究曲面和高维空间的数学结构，学习如何使用微积分中一种强大的工具——de Rham 上同调来分类它们的“洞”和连接属性。"},technicalDescription:{en:"Studying smooth manifolds and de Rham cohomology under the supervision of Professor Yanli Song at WashU. Computing classical examples including spheres, tori, and compact surfaces using Mayer–Vietoris sequences and the Poincar\xe9 lemma. Engaging in weekly research discussions and written expositions.",zh:"在华大宋雁离教授的指导下研究光滑流形和 de Rham 上同调。使用 Mayer–Vietoris 序列和庞加莱引理计算经典例子，包括球面、环面和紧凑表面。参加每周的研究讨论和书面阐释。"},techStack:["Differential Topology","de Rham Cohomology","Mayer–Vietoris","Differential Forms","Smooth Manifolds"],category:{en:"Research",zh:"研究"},metrics:[{en:"Weekly research meetings with Prof. Yanli Song",zh:"每周与宋雁离教授进行研究会议"},{en:"Computing cohomology groups of classical examples",zh:"计算经典例子的上同调群"},{en:"Applying Mayer–Vietoris sequences and long exact sequences",zh:"应用 Mayer–Vietoris 序列和长精确序列"},{en:"Ongoing since June 2025",zh:"自 2025 年 6 月起持续进行"}],dataSources:[{en:"Supervised by Prof. Yanli Song, WashU Department of Mathematics",zh:"由华大数学系宋雁离教授指导"}],reportLink:"#",codeLink:"#"},{id:3,title:{en:"Incorporating Power Dynamic in Cooperation and Defection with RL",zh:"利用强化学习将权力动态纳入合作与背叛"},shortDescription:{en:"Q-learning study of social hierarchy and cooperative behavior",zh:"社会等级与合作行为的 Q-learning 研究"},simpleDescription:{en:"Investigated how power differences between individuals (like social status or resources) affect whether people choose to cooperate or compete, using an AI technique that learns optimal strategies through trial and error.",zh:"研究个人之间的权力差异（如社会地位或资源）如何影响人们选择合作还是竞争，使用人工智能技术通过试错来学习最佳策略。"},technicalDescription:{en:"Utilized reinforcement learning (Q-Table) to study cooperation and defection dynamics in the presence of hierarchical power structures. Investigated how different levels of social hierarchy modulate the emergence and stability of cooperative equilibria in multi-agent game-theoretic settings.",zh:"利用强化学习 (Q-Table) 研究在存在等级权力结构时的合作与背叛动态。研究了不同水平的社会等级如何调节多智能体博弈论设置中合作均衡的出现和稳定性。"},techStack:["Python","Q-Table","Reinforcement Learning","Multi-agent Systems","Game Theory"],category:{en:"Research",zh:"研究"},metrics:[{en:"Q-Table models agent decision-making under hierarchical power",zh:"Q-Table 模型模拟等级权力下的代理决策"},{en:"Investigated link between social hierarchy and cooperation",zh:"研究社会等级与合作之间的联系"},{en:"Multi-agent simulation framework",zh:"多智能体模拟框架"}],dataSources:[{en:"Independent research at Culver Academies, Jul 2022 – Feb 2023",zh:"Culver Academies 独立研究，2022 年 7 月 – 2023 年 2 月"}],reportLink:"#",codeLink:"https://github.com/XinshiFeng"},{id:4,title:{en:"Letter Recognition with SVC, Random Forest and CNN",zh:"利用 SVC、随机森林和卷积神经网络进行字母识别"},shortDescription:{en:"Multi-model ML pipeline for character classification",zh:"多模型机器学习管道，用于字符分类"},simpleDescription:{en:"Built several AI models that can recognize handwritten letters and numbers, and used these models to convert old printed documents into searchable digital text — similar to what OCR software does, but built from scratch.",zh:"构建了几个可以识别手写字母和数字的 AI 模型，并使用这些模型将旧的打印文档转换为可搜索的数字文本——类似于 OCR 软件的功能，但完全是从头开始构建的。"},technicalDescription:{en:"Developed and compared machine learning models for alphabetical letter and digit recognition using Support Vector Classification (SVC), Random Forest, and Convolutional Neural Networks (CNNs). Applied trained models to digitize and convert historical documents into searchable formats through automated character recognition pipelines.",zh:"开发并对比了使用支持向量分类 (SVC)、随机森林和卷积神经网络 (CNN) 的字母和数字识别机器学习模型。应用训练好的模型，通过自动字符识别管道将历史文档数字化并转换为可搜索格式。"},techStack:["Python","Scikit-learn","TensorFlow","CNN","SVM","Random Forest"],category:{en:"Machine Learning",zh:"机器学习"},metrics:[{en:"Three model architectures benchmarked: SVC, RF, CNN",zh:"基准测试了三种模型架构：SVC、随机森林、卷积神经网络"},{en:"Historical document digitization pipeline",zh:"历史文档数字化管道"},{en:"Character-level classification on multiple alphabets",zh:"多种字母表的字符级分类"}],dataSources:[{en:"Independent research at Culver Academies, Jul 2021 – Feb 2022",zh:"Culver Academies 独立研究，2021 年 7 月 – 2022 年 2 月"},{en:"Historical document datasets",zh:"历史文档数据集"}],reportLink:"#",codeLink:"https://github.com/XinshiFeng"},{id:5,title:{en:"Robomaster Computer Vision — Ursaworks Robotics Club",zh:"Robomaster 计算机视觉 — Ursaworks 机器人俱乐部"},shortDescription:{en:"Dataset collection and ML model training for robot competition",zh:"机器人竞赛的数据集收集和机器学习模型训练"},simpleDescription:{en:"Working with a team to build and program robots that can autonomously detect and track targets using cameras and AI, competing in the Robomaster robotics competition.",zh:"与团队合作构建和编程机器人，使其能够使用摄像头和 AI 自主探测和跟踪目标，参加 Robomaster 机器人竞赛。"},technicalDescription:{en:"Contributing to the Computer Vision group at WashU's Ursaworks Robotics Club. Collecting and labeling video datasets for training object detection and tracking models for autonomous robot navigation in the Robomaster Competition. Operating robots during competitions.",zh:"为华大 Ursaworks 机器人俱乐部的计算机视觉小组做出贡献。在 Robomaster 竞赛中收集并标注视频数据集，用于训练自动机器人导航的目标检测和跟踪模型。在竞赛期间操作机器人。"},techStack:["Python","Computer Vision","Object Detection","Video Labeling","ML Training"],category:{en:"Machine Learning",zh:"机器学习"},metrics:[{en:"Weekly collaboration with multi-disciplinary robotics team",zh:"每周与多学科机器人团队合作"},{en:"Dataset collection and labeling for custom CV models",zh:"为自定义计算机视觉模型收集并标注数据集"},{en:"Competition deployment and operation",zh:"比赛部署与操作"},{en:"Robomaster 2024–2025 competition seasons",zh:"Robomaster 2024–2025 赛季"}],dataSources:[{en:"Ursaworks Robotics Club, WashU — Jan 2024 to Present",zh:"华大 Ursaworks 机器人俱乐部 — 2024 年 1 月至今"}],reportLink:"#",codeLink:"https://github.com/XinshiFeng"}],a=[{en:"All",zh:"全部"},{en:"Research",zh:"研究"},{en:"Machine Learning",zh:"机器学习"}]}}]);